import{c as r,Q as i,j as d,m as o}from"./chunks/framework.D0Y1hua4.js";const b=JSON.parse('{"title":"团队建设核心：建队先建己","description":"","frontmatter":{},"headers":[],"relativePath":"notes/培训/组长培训/团队建设核心：建队先建己.md","filePath":"notes/培训/组长培训/团队建设核心：建队先建己.md"}'),p={name:"notes/培训/组长培训/团队建设核心：建队先建己.md"};function a(t,e,n,l,s,g){return i(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="团队建设核心-建队先建己" tabindex="-1">团队建设核心：建队先建己 <a class="header-anchor" href="#团队建设核心-建队先建己" aria-label="Permalink to &quot;团队建设核心：建队先建己&quot;">​</a></h1><h2 id="一、核心答案-自己是一切的起点-🌟" tabindex="-1">一、核心答案：自己是一切的起点 🌟 <a class="header-anchor" href="#一、核心答案-自己是一切的起点-🌟" aria-label="Permalink to &quot;一、核心答案：自己是一切的起点 🌟&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;border-left:4px solid #667eea;"><p style="color:#333;font-size:15px;margin:0;line-height:1.7;">💡 建设团队的第一步，不是招人、不是培训，而是<strong style="color:#667eea;">先建设好自己</strong>。你自己是什么样的人，就会吸引什么样的人，就会带出什么样的团队。</p></div></div><h2 id="二、为什么建队先建己-🤔" tabindex="-1">二、为什么建队先建己？ 🤔 <a class="header-anchor" href="#二、为什么建队先建己-🤔" aria-label="Permalink to &quot;二、为什么建队先建己？ 🤔&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:15px;margin:20px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);color:#333;padding:20px;border-radius:12px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#667eea;">1️⃣ 榜样的力量</p><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p style="font-size:14px;margin:0;line-height:1.6;">团队成员会模仿领导的行为。如果你自己都做不到，如何要求别人做到？<strong style="color:#667eea;">以身作则</strong>是最好的管理。</p></div></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);color:#333;padding:20px;border-radius:12px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#22c55e;">2️⃣ 吸引力法则</p><div style="background:rgba(34,197,94,0.08);padding:12px;border-radius:8px;border-left:4px solid #22c55e;"><p style="font-size:14px;margin:0;line-height:1.6;">优秀的人吸引优秀的人。你自己优秀了，才能吸引优秀的人加入你的团队。<strong style="color:#22c55e;">物以类聚，人以群分</strong>。</p></div></div><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);color:#333;padding:20px;border-radius:12px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#f59e0b;">3️⃣ 信任的基础</p><div style="background:rgba(245,158,11,0.08);padding:12px;border-radius:8px;border-left:4px solid #f59e0b;"><p style="font-size:14px;margin:0;line-height:1.6;">团队成员信任你，是因为你值得信任。你的能力、人品、态度，决定了团队成员对你的信任程度。</p></div></div><div style="background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);color:#333;padding:20px;border-radius:12px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#3b82f6;">4️⃣ 能力的传承</p><div style="background:rgba(59,130,246,0.08);padding:12px;border-radius:8px;border-left:4px solid #3b82f6;"><p style="font-size:14px;margin:0;line-height:1.6;">你只能教别人你自己会的东西。你自己能力不足，就无法培养出优秀的团队成员。</p></div></div></div><h2 id="三、建己的核心维度-📊" tabindex="-1">三、建己的核心维度 📊 <a class="header-anchor" href="#三、建己的核心维度-📊" aria-label="Permalink to &quot;三、建己的核心维度 📊&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;flex:1;min-width:300px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#667eea;">💪 能力建设</p><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>业务能力</strong>：销售技能、客户沟通</p><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>管理能力</strong>：团队管理、人才培养</p><p style="font-size:14px;margin:0;line-height:1.6;"><strong>综合能力</strong>：解决问题、统筹规划</p></div></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:20px;border-radius:12px;flex:1;min-width:300px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#22c55e;">🧠 心态建设</p><div style="background:rgba(34,197,94,0.08);padding:12px;border-radius:8px;border-left:4px solid #22c55e;"><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>积极心态</strong>：面对困难不放弃</p><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>学习心态</strong>：持续成长、不断进步</p><p style="font-size:14px;margin:0;line-height:1.6;"><strong>责任心态</strong>：勇于承担、不推诿</p></div></div><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);padding:20px;border-radius:12px;flex:1;min-width:300px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#f59e0b;">🎯 目标建设</p><div style="background:rgba(245,158,11,0.08);padding:12px;border-radius:8px;border-left:4px solid #f59e0b;"><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>个人目标</strong>：清晰的发展方向</p><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>团队目标</strong>：带领团队达成业绩</p><p style="font-size:14px;margin:0;line-height:1.6;"><strong>长期目标</strong>：成为经理、开拓市场</p></div></div><div style="background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);padding:20px;border-radius:12px;flex:1;min-width:300px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#3b82f6;">🤝 品格建设</p><div style="background:rgba(59,130,246,0.08);padding:12px;border-radius:8px;border-left:4px solid #3b82f6;"><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>诚信</strong>：说到做到、言行一致</p><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>公正</strong>：公平对待每个人</p><p style="font-size:14px;margin:0;line-height:1.6;"><strong>担当</strong>：为团队负责、为结果负责</p></div></div></div><h2 id="四、如何建己-🛠️" tabindex="-1">四、如何建己？ 🛠️ <a class="header-anchor" href="#四、如何建己-🛠️" aria-label="Permalink to &quot;四、如何建己？ 🛠️&quot;">​</a></h2><div style="display:flex;flex-direction:column;gap:12px;margin:20px 0;"><div style="display:flex;align-items:center;gap:15px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);color:#333;padding:18px 20px;border-radius:12px;"><div style="background:rgba(102,126,234,0.15);padding:10px 18px;border-radius:10px;font-weight:bold;font-size:16px;white-space:nowrap;color:#667eea;">1</div><div style="flex:1;"><p style="margin:0;font-weight:bold;font-size:18px;">📚 持续学习</p><p style="margin:5px 0 0 0;font-size:14px;">不断学习业务知识、管理技能，提升自己的综合能力</p></div></div><div style="display:flex;align-items:center;gap:15px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);color:#333;padding:18px 20px;border-radius:12px;"><div style="background:rgba(34,197,94,0.15);padding:10px 18px;border-radius:10px;font-weight:bold;font-size:16px;white-space:nowrap;color:#22c55e;">2</div><div style="flex:1;"><p style="margin:0;font-weight:bold;font-size:18px;">💪 实践锻炼</p><p style="margin:5px 0 0 0;font-size:14px;">在实战中磨练自己，用结果证明自己的能力</p></div></div><div style="display:flex;align-items:center;gap:15px;background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);color:#333;padding:18px 20px;border-radius:12px;"><div style="background:rgba(245,158,11,0.15);padding:10px 18px;border-radius:10px;font-weight:bold;font-size:16px;white-space:nowrap;color:#f59e0b;">3</div><div style="flex:1;"><p style="margin:0;font-weight:bold;font-size:18px;">🪞 自我反思</p><p style="margin:5px 0 0 0;font-size:14px;">定期反思自己的不足，持续改进和提升</p></div></div><div style="display:flex;align-items:center;gap:15px;background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);color:#333;padding:18px 20px;border-radius:12px;"><div style="background:rgba(59,130,246,0.15);padding:10px 18px;border-radius:10px;font-weight:bold;font-size:16px;white-space:nowrap;color:#3b82f6;">4</div><div style="flex:1;"><p style="margin:0;font-weight:bold;font-size:18px;">🤝 向优秀学习</p><p style="margin:5px 0 0 0;font-size:14px;">向优秀的领导、同事学习，借鉴他们的经验和方法</p></div></div><div style="display:flex;align-items:center;gap:15px;background:rgba(236,72,153,0.06);border:1px solid rgba(236,72,153,0.15);color:#333;padding:18px 20px;border-radius:12px;"><div style="background:rgba(236,72,153,0.15);padding:10px 18px;border-radius:10px;font-weight:bold;font-size:16px;white-space:nowrap;color:#ec4899;">5</div><div style="flex:1;"><p style="margin:0;font-weight:bold;font-size:18px;">🎯 设定高标准</p><p style="margin:5px 0 0 0;font-size:14px;">对自己设定高标准，不断挑战和突破自己</p></div></div></div><h2 id="五、建己与建队的关系-🔄" tabindex="-1">五、建己与建队的关系 🔄 <a class="header-anchor" href="#五、建己与建队的关系-🔄" aria-label="Permalink to &quot;五、建己与建队的关系 🔄&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="display:flex;flex-wrap:wrap;gap:12px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #667eea;"><p style="color:#667eea;font-weight:bold;margin:0 0 8px 0;">🏠 建己是地基</p><p style="color:#333;font-size:14px;margin:0;line-height:1.6;">自己的能力、心态、品格是团队建设的地基。地基不稳，团队难以长久。</p></div><div style="background:rgba(34,197,94,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #22c55e;"><p style="color:#22c55e;font-weight:bold;margin:0 0 8px 0;">🏗️ 建队是建筑</p><p style="color:#333;font-size:14px;margin:0;line-height:1.6;">在稳固的地基上，才能建设出优秀的团队。团队的高度取决于地基的深度。</p></div><div style="background:rgba(245,158,11,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #f59e0b;"><p style="color:#f59e0b;font-weight:bold;margin:0 0 8px 0;">🔄 相互促进</p><p style="color:#333;font-size:14px;margin:0;line-height:1.6;">建己促进建队，建队反过来促进建己。两者相辅相成，共同成长。</p></div></div></div><h2 id="六、总结-📝" tabindex="-1">六、总结 📝 <a class="header-anchor" href="#六、总结-📝" aria-label="Permalink to &quot;六、总结 📝&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;border-left:4px solid #667eea;"><p style="color:#333;font-size:15px;margin:0;line-height:1.7;">📌 <strong style="color:#667eea;">建队先建己</strong>。在建设团队之前，先建设好自己。你的能力、心态、目标、品格，决定了你能吸引什么样的人，能带出什么样的团队。<strong style="color:#667eea;">自己优秀，团队才能优秀</strong>。</p></div></div>',13)])])}const f=r(p,[["render",a]]);export{b as __pageData,f as default};
